<script>
var AT=(function(){
  var S={th:'dark',ln:'en',cHer:false,cBir:false,cBrn:false,cRol:false,cLoc:false,cScn:false,cFac:false,cTit:false,skl:[],rel:[],stats:{}};
  var STATS=[
    ['ODM Mastery','odm','Maneuverability, anchor instinct, fluency in three dimensions.'],
    ['Hand-to-Hand','hth','Blade, fist, knife, throw.'],
    ['Marksmanship','mks','Rifle, pistol, cannon, Thunder Spear.'],
    ['Tactics','tac','Command read, terrain sense, gambit.'],
    ['Intelligence','int','Pattern, deduction, breadth of learning.'],
    ['Resolve','rsv','Will under fire. The heart, when it must be devoted.'],
    ['Constitution','con','Endurance. The body, when blood has gone cold.'],
    ['Influence','inf','Standing, connections, the reach of your name.']
  ];
  var STATS_TH=[
    ['การใช้ ODM','odm','การเคลื่อนไหวสามมิติ ความว่องไวบนสายเหล็ก'],
    ['ต่อสู้ระยะประชิด','hth','ดาบ มีด หมัด การคลุก'],
    ['การยิงปืน','mks','ปืนยาว ปืนสั้น ปืนใหญ่ ทันเดอร์สเปียร์'],
    ['ยุทธวิธี','tac','การวางแผน อ่านสนาม ตัดสินใจ'],
    ['สติปัญญา','int','ความรู้ การวิเคราะห์ ตรรกะ'],
    ['ความมุ่งมั่น','rsv','ใจกล้าใต้ห่ากระสุน หัวใจที่อุทิศได้'],
    ['ร่างกาย','con','พละกำลังและความอดทน'],
    ['อิทธิพล','inf','สถานะ เครือข่าย ความน่าเชื่อถือ']
  ];

  function g(id){return document.getElementById(id)}
  function updCus(K){
    var flag=S['c'+K];
    var btn=g('btn'+K), sel=g('f'+K+'Pre'), inp=g('f'+K+'Cus');
    if(btn) btn.textContent = flag ? (S.ln==='th'?'พรีเซ็ต':'PRESETS') : (S.ln==='th'?'กำหนดเอง':'CUSTOM');
    if(sel) sel.style.display = flag?'none':'block';
    if(inp) inp.style.display = flag?'block':'none';
  }

  function bSt(){
    var b=g('statBox'); if(!b)return; b.innerHTML='';
    var src=(S.ln==='th')?STATS_TH:STATS;
    src.forEach(function(s){
      var cur=S.stats[s[1]]||5;
      var w=document.createElement('div'); w.className='sl-wrap';
      var t=document.createElement('div'); t.className='sl-top';
      var l=document.createElement('div'); l.className='sl-n'; l.textContent=s[0];
      var v=document.createElement('div'); v.className='sl-v'; v.innerHTML='<span id="v_'+s[1]+'">'+cur+'</span><span class="of">/10</span>';
      t.appendChild(l); t.appendChild(v);
      var d=document.createElement('div'); d.className='sl-d'; d.textContent=s[2];
      var barWrap=document.createElement('div'); barWrap.className='sl-bar';
      for(var i=1;i<=10;i++){
        var tk=document.createElement('div'); tk.className='sl-tick'; tk.dataset.v=i;
        if(i<=cur) tk.classList.add('on');
        if(i>=9 && i<=cur) tk.classList.add('crit');
        (function(val,key,wrap){
          tk.addEventListener('click',function(){
            S.stats[key]=val;
            var vv=g('v_'+key); if(vv) vv.textContent=val;
            var ticks=wrap.querySelectorAll('.sl-tick');
            ticks.forEach(function(tt){
              var n=parseInt(tt.dataset.v,10);
              tt.classList.toggle('on',n<=val);
              tt.classList.toggle('crit',n>=9 && n<=val);
            });
          });
        })(i,s[1],barWrap);
        barWrap.appendChild(tk);
      }
      w.appendChild(t); w.appendChild(d); w.appendChild(barWrap); b.appendChild(w);
    });
  }

  function rLst(type){
    var arr=S[type], wrap=g(type==='skl'?'lSkl':'lRel'); if(!wrap)return;
    wrap.innerHTML='';
    var empTh = type==='skl'?'ยังไม่มีความเชี่ยวชาญที่บันทึก':'ยังไม่มีสายสัมพันธ์ที่บันทึก';
    var empEn = type==='skl'?'No specialties yet logged.':'No bonds yet logged.';
    if(!arr.length){ wrap.innerHTML='<div class="empty">'+(S.ln==='th'?empTh:empEn)+'</div>'; return; }
    arr.forEach(function(item, idx){
      var c=document.createElement('div'); c.className='lst-c';
      var i=document.createElement('div'); i.className='lst-i';
      var n=document.createElement('div'); n.className='lst-n'; n.textContent=item.n;
      var t=document.createElement('div'); t.className='lst-t'; t.textContent=item.t;
      i.appendChild(n); i.appendChild(t);
      if(item.d){ var d=document.createElement('div'); d.className='lst-d'; d.textContent=item.d; i.appendChild(d); }
      var btn=document.createElement('button'); btn.className='lst-del'; btn.innerHTML='&times;';
      btn.onclick=function(){ arr.splice(idx,1); rLst(type); };
      c.appendChild(i); c.appendChild(btn); wrap.appendChild(c);
    });
  }

  function cVal(id){ var e=g(id); return e?(e.value||'').trim():''; }
  function tVal(K){ return S['c'+K] ? cVal('f'+K+'Cus') : cVal('f'+K+'Pre'); }

  return {
    init:function(){ STATS.forEach(function(s){S.stats[s[1]]=5;}); bSt(); rLst('skl'); rLst('rel'); },
    th:function(){ S.th=S.th==='dark'?'light':'dark'; g('app').className='app '+(S.th==='light'?'lt':''); },
    ln:function(){
      S.ln=S.ln==='en'?'th':'en'; var th=S.ln==='th';
      g('btnLn').textContent=th?'TH':'EN';
      g('hS').textContent=th?'— แฟ้มประจำกองพัน —':'— Regimental Dossier —';
      g('stamp1').textContent=th?'ลับ':'CLASSIFIED';
      g('stamp2').textContent=th?'เฉพาะผู้บัญชาการ':'FOR COMMAND ONLY';
      g('tb1').innerHTML='<span class="tab-icon">✦</span>'+(th?'ตัวตน':'Identity');
      g('tb2').innerHTML='<span class="tab-icon">⚔</span>'+(th?'สังกัด':'Service');
      g('tb3').innerHTML='<span class="tab-icon">⚙</span>'+(th?'ศักยภาพ':'Capability');
      g('tb4').innerHTML='<span class="tab-icon">⚑</span>'+(th?'สายสัมพันธ์':'Bonds');
      g('f1').textContent=th?'แฟ้ม ๑ — การพิสูจน์ตัวตน':'FILE I — IDENTIFICATION';
      g('f2').textContent=th?'แฟ้ม ๒ — สังกัดและฐานะ':'FILE II — SERVICE & STATION';
      g('f3').textContent=th?'แฟ้ม ๓ — การประเมินศักยภาพ':'FILE III — CAPABILITY ASSESSMENT';
      g('f4').textContent=th?'แฟ้ม ๔ — พันธะ คำสาบาน และเงา':'FILE IV — BONDS, OATHS & SHADOW';
      g('d1').textContent=th?'ว่าด้วยชื่อ สายเลือด และเครื่องหมายแห่งกำเนิด':'By name, blood, and the marks of birth.';
      g('d2').textContent=th?'ว่าด้วยกองพัน ยศ และที่พักพิง':'By branch, rank, and the roof beneath which they sleep.';
      g('d3').textContent=th?'วัดจาก ๑ ถึง ๑๐ — ลงนามโดยครูฝึก ยืนยันในสนามรบ':'Measured 1 to 10. Inked by the drill instructor. Verified in the field.';
      g('d4').textContent=th?'ใจถูกสาบานไว้ที่ใด มือใดถูกยื่นออก ดาบใดลับไว้สำหรับผู้ใด':'Where the heart is sworn, what hand is offered, what blade is sharpened against whom.';
      g('hAlg').textContent=th?'ความจงรักภักดีและเจตนา':'Devotion & Intent';
      g('hSkl').textContent=th?'ความเชี่ยวชาญและการฝึก':'Specialties & Training';
